    // Create a copy and sort it to avoid modifying the original array
    const sorted = [...nums].sort((a, b) => a - b);
    const length = sorted.length;

    if (length % 2 === 1) {
        // Odd count: return the middle element
        return sorted[Math.floor(length / 2)];
    } else {
        // Even count: return average of two middle elements
        const mid1 = sorted[length / 2 - 1];
        const mid2 = sorted[length / 2];
        return (mid1 + mid2) / 2;
