```javascript
/**
 * Calculates the Levenshtein distance between two strings.
 * The Levenshtein distance is the minimum number of single-character edits 
 * (insertions, deletions, or substitutions) required to change one word into the other.
 * 
 * @param {string} a The first string.
 * @param {string} b The second string.
 * @returns {number} The edit distance between a and b.
 */
const editDistance = (a, b) => {
    const m = a.length;
    const n = b.length;

    // Create a 2D array (m+1) x (n+1) to store the distances
    const dp = Array(m + 1).fill(0).map(() => Array(n + 1).fill(0));

    // Initialize the first row and column
    // dp[i][0] = i (cost of deleting i characters from a to get an empty string)
    for (let i = 0; i <= m; i++) {
        dp[i][0] = i;
    }

    // dp[0][j] = j (cost of inserting j characters into an empty string to get b)
    for (let j = 0; j <= n; j++) {
        dp[0][j] = j;
    }

    // Fill the DP table
    for (let i = 1; i <= m; i++) {
        for (let j = 1; j <= n; j++) {
            // Cost of substitution: 0 if characters match, 1 otherwise
            const cost = (a[i - 1] === b[j - 1]) ? 0 : 1;

            dp[i][j] = Math.min(
                dp[i - 1][j] + 1,      // Deletion (from a)
                dp[i][j - 1] + 1,      // Insertion (into a, or deletion from b)
                dp[i - 1][j - 1] + cost // Substitution or Match
            );
        }
    }

    // The bottom-right cell contains the final edit distance
    return dp[m][n];
};
