/**
 * Calculates the Levenshtein distance (edit distance) between two strings.
 * @param {string} a The first string.
 * @param {string} b The second string.
 * @returns {number} The minimum number of operations (insertions, deletions, substitutions).
 */
const editDistance = (a, b) => {
    const m = a.length;
    const n = b.length;

    // Create a 2D array (m+1) x (n+1)
    const dp = Array(m + 1).fill(0).map(() => Array(n + 1).fill(0));

    // Initialize the first row and column
    // dp[i][0] = i (i deletions to transform a[0..i-1] to empty string)
    for (let i = 0; i <= m; i++) {
        dp[i][0] = i;
    }
    // dp[0][j] = j (j insertions to transform empty string to b[0..j-1])
    for (let j = 0; j <= n; j++) {
        dp[0][j] = j;
    }

    // Fill the DP table
    for (let i = 1; i <= m; i++) {
        for (let j = 1; j <= n; j++) {
            // Cost of substitution: 0 if characters match, 1 otherwise
            const cost = (a[i - 1] === b[j - 1]) ? 0 : 1;

            dp[i][j] = Math.min(
                dp[i - 1][j] + 1,      // Deletion (from a)
                dp[i][j - 1] + 1,      // Insertion (into a)
                dp[i - 1][j - 1] + cost // Substitution/Match
            );
        }
    }

    return dp[m][n];
};
