/**
 * Calculates the Levenshtein distance (edit distance) between two strings.
 * @param {string} a The first string.
 * @param {string} b The second string.
 * @returns {number} The minimum number of single-character insertions, deletions, or substitutions.
 */
const editDistance = (a, b) => {
    const m = a.length;
    const n = b.length;

    // Create a DP table D[m+1][n+1]
    // D[i][j] stores the edit distance between a[0...i-1] and b[0...j-1]
    const dp = Array(m + 1).fill(0).map(() => Array(n + 1).fill(0));

    // Initialization: Base cases
    // Distance of any string to an empty string
    for (let i = 0; i <= m; i++) {
        dp[i][0] = i; // i deletions
    }
    for (let j = 0; j <= n; j++) {
        dp[0][j] = j; // j insertions
    }

    // Fill the DP table
    for (let i = 1; i <= m; i++) {
        for (let j = 1; j <= n; j++) {
            // Cost of substitution: 0 if characters match, 1 otherwise
            const cost = (a[i - 1] === b[j - 1]) ? 0 : 1;

            // Recurrence relation:
            // 1. Deletion: dp[i-1][j] + 1
            // 2. Insertion: dp[i][j-1] + 1
            // 3. Substitution/Match: dp[i-1][j-1] + cost
            dp[i][j] = Math.min(
                dp[i - 1][j] + 1,      // Deletion
                dp[i][j - 1] + 1,      // Insertion
                dp[i - 1][j - 1] + cost // Substitution or Match
            );
        }
    }

    return dp[m][n];
};
