function editDistance(a, b) {
    const m = a.length;
    const n = b.length;

    // If one string is empty, distance is the length of the other
    if (m === 0) return n;
    if (n === 0) return m;

    // Initialize the previous row of distances
    // prev[j] represents the distance between empty string and b[0..j-1]
    let prev = new Array(n + 1).fill(0);
    for (let j = 0; j <= n; j++) {
        prev[j] = j;
    }

    // Iterate through each character of string a
    for (let i = 1; i <= m; i++) {
        // Initialize the current row
        // curr[0] represents the distance between a[0..i-1] and empty string
        let curr = new Array(n + 1).fill(0);
        curr[0] = i;

        for (let j = 1; j <= n; j++) {
            // If characters match, cost is 0, otherwise 1
            const cost = a[i - 1] === b[j - 1] ? 0 : 1;

            // Calculate minimum of:
            // 1. Deletion (prev[j] + 1)
            // 2. Insertion (curr[j - 1] + 1)
            // 3. Substitution (prev[j - 1] + cost)
            curr[j] = Math.min(
                prev[j] + 1,
                curr[j - 1] + 1,
                prev[j - 1] + cost
            );
        }

        // Move to the next row
        prev = curr;
    }

    return prev[n];
