function isValid(s) {
  const stack = [];
  for (const ch of s) {
    if (ch === '(' || ch === '[' || ch === '{') {
      stack.push(ch);
    } else {
      if (stack.length === 0) return false;
      const top = stack.pop();
      if ((ch === ')' && top !== '(') ||
          (ch === ']' && top !== '[') ||
          (ch === '}' && top !== '{')) {
        return false;
      }
    }
  }
  return stack.length === 0;
}
