function lengthOfLongestSubstring(s) {
    const map = new Map();
    let max = 0;
    let left = 0;
    for (let right = 0; right < s.length; right++) {
        const ch = s[right];
        if (map.has(ch)) {
            left = Math.max(left, map.get(ch) + 1);
        }
        map.set(ch, right);
        max = Math.max(max, right - left + 1);
    }
    return max;
}
